import React, { Component } from 'react'
import '../scss/App.scss'
import Navbar from './MyNavbar'
import Section from './Section'
import { Container } from 'react-bootstrap';
import { LinearProgress } from '@material-ui/core'
import { Route, BrowserRouter, Switch } from 'react-router-dom'
import $ from 'jquery'

// import About from '../pages/About'
import Contact from '../pages/Contact'
import Main from '../pages/Main';
import Blog from '../pages/Blog'

class App extends Component {

	constructor(props){
		super(props)
		this.state = {
			isLoading: true
		}
	}

	componentDidMount(){
		setTimeout(() => {
			$('.header-wrapper-wrapper').animate({'top': '0', 'transition': '0.2s ease-in-out'})
			this.setState({
				isLoading: false,
			})
		}, 2000)
	}

	render(){
		return(
			<BrowserRouter>
				{this.state.isLoading ? <LinearProgress id="progressBar" variant="indeterminate" color="primary" style={{ position: "fixed", width: "100%", top: "0" }} /> : ""}
				<div className="header-wrapper-wrapper" style={{ position: 'fixed', width: '100%', top: '4px' }}>
					<div id="header-wrapper">
						<Navbar />
						<Section type="header" />
					</div>
				</div>
				<div id="full-wrapper">
					<Container style={{ width: '70%' }} id="container-org">
						{/* <Content /> */}
						<Switch>
							<Route exact path="/" component={Main} />
							{/* <Route path="/about" component={About} /> */}
							<Route exact path="/contact" component={Contact} />
							<Route path="/blog" component={Blog} />
						</Switch>
					</Container>
				</div>
			</BrowserRouter>
		)
	}

}

export default App
