import React, {Component} from 'react'
import { Card, Form, Row, Col, Button, Alert } from 'react-bootstrap';
import { TextField } from '@material-ui/core';
import MyData from '../MyData'
import axios from 'axios'


class Contact extends Component {

	constructor(props){
		super(props)
		this.state = {
			error: false,
			message: '',
			messageSent: false,
		}
	}

	validate = () => {
		let name = document.querySelector('#input_name')
		let email = document.querySelector('#input_email')
		let message = document.querySelector('#input_message')
		let sendBtn = document.getElementById('sendBtn')
		sendBtn.innerHTML = 'Please wait...'
		this.postData(name.value, email.value, message.value, sendBtn)
	}

	postData = (name, email, message, sendBtn) => {
		axios.post(MyData.api_url + 'main.php?request=save_contact', {
			name,
			email,
			message
		}).then(res => {
			this.setState({
				messageSent: true
			})
			sendBtn.innerHTML = 'Send'
		}).catch(error => {
			console.error(error)
			this.setState({
				messageSent: false,
				error: true,
				message: 'Something went wrong.'
			})
			sendBtn.innerHTML = 'Send'
		})
	}

	render(){
		return(
			<React.Fragment>
				<div className="content-wrapper">
					<Card body className="first-card">
						<h3 className="mb-4">Do you want to tell me something?</h3>
						<Form autoComplete="off">
							<Row className="justify-content-center">
								<Col lg={6} md={6} sm={12} className="mb-4">
									<TextField id="input_name" label="Yout Name" variant="outlined" className="form-control" />
								</Col>
								<Col lg={6} md={6} sm={12} className="mb-2">
									<TextField id="input_email" label="Yout Email" variant="outlined" className="form-control" />
								</Col>
								<Col lg={12} md={12} sm={12} className="mt-4">
									<TextField multiline rows={6} id="input_message" label="Your Message" variant="outlined" className="form-control form-input-message" />
								</Col>
								<Button id="sendBtn" variant="success" onClick={() => this.validate()} style={{ marginTop: '130px' }} className="float-right">Send</Button>
							</Row>
							{this.state.error ? <Alert variant="danger" className="mt-3"> {this.state.message} </Alert> : ""}
							{this.state.messageSent ? <Alert variant="success" className="mt-3"> Your message has sent. </Alert> : ""}
						</Form>
					</Card>
				</div>
			</React.Fragment>
		)
	}

}

export default Contact