import React, { Component } from 'react'
import { Container, Row, Col, Card, Alert } from 'react-bootstrap';
import { Icon } from '@material-ui/core';
import MyData from '../MyData'

class Blog extends Component {

	constructor(props){
		super(props)
		this.state = {
			posts: [],
			postsLoaded: false
		}
	}

	componentDidMount(){
		fetch(`${MyData.api_url}main.php?request=show_blog_posts`).then(res => res.json()).then(data => {
			this.setState({
				posts: eval(data.data),
				postsLoaded: true
			})
		}).catch(error => console.error(error))
	}

	renderPosts = data => {
		return(
			data.map((data, id) => (
				<Col lg={4} md={6} sm={12} key={id} className="mb-4">
					<Card className="post-card-out">
						<Card.Img variant="top" src={data.picture} />
						<Card className="pt-3 post-card-in">
							<Card.Title className="h6">
								<a href="/">{data.title}</a>
							</Card.Title>
						</Card>
					</Card>
				</Col>
			))
		)
	}

	render(){
		return(
			<React.Fragment>
				<div className="content-wrapper">

					<Container>
						<Row>
							<Col lg={12} md={12} sm={12}>
								<Card className="first-card text-center">
									<h3><Icon>create</Icon> Blog Posts</h3>
								</Card>
							</Col>
							<Container>
								<Row className="justify-content-center">
									{this.renderPosts(this.state.posts)}
									{(!this.state.postsLoaded) ? <Alert variant="light">Please wait...</Alert> : null}
								</Row>
							</Container>
						</Row>
					</Container>

				</div>
			</React.Fragment>
		)
	}

}

export default Blog